// pkg/migration/migration.go

package migration

import (
    "airwatch/uem/gumdrop-ingestion/pkg/log"
    "airwatch/uem/gumdrop-ingestion/internal/pkg/repository"
    "time"
)

// Migration defines the contract that all data migrations must implement
type Migration interface {
    // ID returns a unique identifier for the migration (should include version)
    ID() string

    // Description returns a human-readable description of what the migration does
