package data_migration

import (
    "airwatch/uem/gumdrop-ingestion/internal/pkg/consul"
    "airwatch/uem/gumdrop-ingestion/pkg/log"
    "github.com/pkg/errors"
    json "github.com/json-iterator/go"
    "time"
)

const (
    // MigrationHistoryKey is the Consul key where migration history is stored
    MigrationHistoryKey = "migration/history"
)

// Storage handles persistence of migration history
type Storage struct {
    consulClient consul.Client
}

// NewStorage creates a new migration storage
func NewStorage(consulClient consul.Client) *Storage {
    return &Storage{
        consulClient: consulClient,
    }
}

// GetExecutedMigrations retrieves the list of migrations that have been executed
func (s *Storage) GetExecutedMigrations(ctx *log.Context) ([]MigrationInfo, error) {
    const functionName = "data_migration.Storage.GetExecutedMigrations"

    // Get migration history from Consul
    kvPair, err := s.consulClient.GetKey(MigrationHistoryKey)
    if err != nil {
        return nil, errors.Wrap(err, functionName)
    }

    // If key doesn't exist, return empty history
    if kvPair == nil || len(kvPair.Value) == 0 {
        return []MigrationInfo{}, nil
    }

    // Unmarshal migration history
    var history MigrationHistory
    if err := json.Unmarshal(kvPair.Value, &history); err != nil {
        return nil, errors.Wrap(err, functionName)
    }

    return history.Migrations, nil
}

// RecordMigration records a successful migration execution in the history
func (s *Storage) RecordMigration(ctx *log.Context, migration Migration, startTime time.Time) error {
    const functionName = "data_migration.Storage.RecordMigration"

    // Get current migration history
    migrations, err := s.GetExecutedMigrations(ctx)
    if err != nil {
        return errors.Wrap(err, functionName)
    }

    // Create migration info
    info := MigrationInfo{
        Name:        migration.Name(),
        Version:     migration.Version(),
        ID:          migration.ID(),
        Description: migration.Description(),
        ExecutedAt:  time.Now(),
        DurationMs:  time.Since(startTime).Milliseconds(),
    }

    // Add new migration to history
    migrations = append(migrations, info)

    // Create history object
    history := MigrationHistory{
        Migrations: migrations,
    }

    // Save updated history
    if err := s.consulClient.PutKey(MigrationHistoryKey, history); err != nil {
        return errors.Wrap(err, functionName)
    }

    log.Infow(ctx, "Recorded migration execution in history", 
        "migration_id", migration.ID(),
        "total_migrations", len(migrations))

    return nil
}

// HasMigrationExecuted checks if a migration has already been executed
func (s *Storage) HasMigrationExecuted(ctx *log.Context, migrationID string) (bool, error) {
    const functionName = "data_migration.Storage.HasMigrationExecuted"

    // Get executed migrations
    migrations, err := s.GetExecutedMigrations(ctx)
    if err != nil {
        return false, errors.Wrap(err, functionName)
    }

    // Check if migration ID exists in history
    for _, m := range migrations {
        if m.ID == migrationID {
            return true, nil
        }
    }

    return false, nil
}
```

Yes, this implementation is using a single file approach:

1. We use one Consul key (`migration/history`) to store all migration history
2. The entire migration history is stored in a single JSON document
3. Each time we record a new migration, we:
   - Read the entire migration history document
   - Append the new migration to the list
   - Write the entire document back to Consul

This approach is simple and works well for a moderate number of migrations. If you expect to have hundreds or thousands of migrations, we might want to reconsider this approach, but for most systems, this single document approach is perfectly fine.

