func publish(
	logContext *log.Context,
	noSqlMgmtRepository repository.NoSqlMgmtRepository,
	consulClient consul.Client,
	scriptRootDir string,
) (actionChanel <-chan error, err error) {
	return consulClient.RunOnceAction(
		logContext,
		publishSyncKey,
		func() error {
			published, err := opensearchInternal.PublishIndices(
				logContext,
				noSqlMgmtRepository,
			)
			if err != nil {
				return err
			} else if published {
				templatedScriptsDirPath := path.Join(scriptRootDir, opensearchInternal.TemplatedScriptsRootDirName)
				opensearchInternal.PublishTemplatedScripts(logContext, noSqlMgmtRepository, templatedScriptsDirPath)

				// Run data migrations after successful publish
				// You may need to cast noSqlMgmtRepository to repository.NoSqlRepository
				// depending on your interface hierarchy
				noSqlRepo := noSqlMgmtRepository.(repository.NoSqlRepository)
				if err := data_migration.RunMigrations(
					logContext,
					noSqlRepo,
					consulClient,
				); err != nil {
					return err
				}
			}

			return nil
		},
		func() error {
			opensearchInternal.CheckPublished(logContext, noSqlMgmtRepository)

			return nil
		},
	)
}
